Substituí a voz do navegador (que era robótica) pela **Gemini Text-to-Speech**, que usa modelos neurais avançados para gerar uma narração muito mais natural, fluida e humana.

**O que foi feito:**
1.  **Nova Voz Natural:** Implementei a API de áudio do Gemini usando a voz **"Puck"**, que tem um tom calmo e adequado para leitura.
2.  **Reprodução Inteligente:** O sistema agora baixa o áudio do versículo, decodifica os dados PCM (raw audio) e toca com alta qualidade.
3.  **Indicadores de Estado:** Adicionei um indicador de "Carregando áudio..." (spinner) no botão de cada versículo para você saber quando ele está baixando a voz.

Aqui estão as alterações:

# Updated files:

## services/geminiService.ts

Adiciona a função `getVerseAudio` que conecta ao modelo `gemini-2.5-flash-preview-tts`.

```typescript
import { GoogleGenAI, Type } from "@google/genai";
import { Verse } from '../types';

const apiKey = process.env.API_KEY || '';
// Helper to avoid crashing if no key (will show error in UI)
const getAI = () => {
    if (!apiKey) {
        console.error("API Key is missing");
        return null;
    }
    return new GoogleGenAI({ apiKey });
};

// Função auxiliar robusta para extrair JSON vindo de LLMs
const cleanJsonResponse = (text: string) => {
  // Tenta encontrar um bloco de código JSON explícito
  const matchJson = text.match(/```json\s*([\s\S]*?)\s*```/);
  if (matchJson) return matchJson[1].trim();

  // Tenta encontrar qualquer bloco de código
  const matchCode = text.match(/```\s*([\s\S]*?)\s*```/);
  if (matchCode) return matchCode[1].trim();

  // Se não encontrar blocos, limpa espaços e tenta usar o texto puro
  return text.trim();
};

export const fetchChapterContent = async (bookName: string, chapterNumber: number, retryCount = 0): Promise<{ verses: Verse[], summary: string }> => {
  const ai = getAI();
  if (!ai) throw new Error("Chave de API não configurada.");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      // Alterado para "Almeida" genérica ou domínio público para evitar bloqueio de Recitation (Copyright)
      contents: `Livro: ${bookName}, Capítulo: ${chapterNumber}. Forneça o texto bíblico completo em Português (versão Almeida de domínio público ou equivalente).`,
      config: {
        systemInstruction: `Você é uma API bíblica. Retorne o conteúdo EXATO e COMPLETO do capítulo solicitado em JSON estrito.
        Não abrevie, não pule versículos.

        Formato de Saída:
        {
          "verses": [{"number": 1, "text": "..."}, ...],
          "summary": "Resumo breve."
        }`,
        safetySettings: [
          { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' },
          { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_NONE' },
          { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
          { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' },
        ],
        maxOutputTokens: 8192, 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            verses: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  number: { type: Type.INTEGER },
                  text: { type: Type.STRING }
                },
                required: ["number", "text"]
              }
            },
            summary: {
              type: Type.STRING,
              description: "Um breve resumo do contexto teológico ou narrativo deste capítulo."
            }
          },
          required: ["verses", "summary"]
        }
      }
    });

    if (response.text) {
      try {
        const cleanedText = cleanJsonResponse(response.text);
        const data = JSON.parse(cleanedText);

        // Validação básica
        if (!data.verses || !Array.isArray(data.verses) || data.verses.length === 0) {
            throw new Error("Estrutura de versículos inválida ou vazia.");
        }

        return data;
      } catch (parseError) {
        console.error("Erro ao fazer parse do JSON:", parseError);
        // Se falhar no parse, tentamos novamente se ainda tivermos tentativas
        if (retryCount < 2) {
             console.log(`Erro de parse. Retentando... (${retryCount + 1}/3)`);
             return fetchChapterContent(bookName, chapterNumber, retryCount + 1);
        }
        throw new Error("Recebemos os dados, mas houve um erro ao processá-los.");
      }
    }

    // Se response.text vier vazio (bloqueio ou falha)
    if (retryCount < 2) {
        console.warn(`Resposta vazia. Retentando... (${retryCount + 1}/3)`);
        // Backoff simples
        await new Promise(resolve => setTimeout(resolve, 1000));
        return fetchChapterContent(bookName, chapterNumber, retryCount + 1);
    }

    throw new Error("O modelo não retornou texto (conteúdo vazio) após múltiplas tentativas.");

  } catch (error) {
    console.error(`Erro detalhado ao buscar capítulo (Tentativa ${retryCount + 1}):`, error);

    // Se for um erro de rede ou API, tenta novamente
    if (retryCount < 2) {
        await new Promise(resolve => setTimeout(resolve, 1500));
        return fetchChapterContent(bookName, chapterNumber, retryCount + 1);
    }

    if (error instanceof Error) {
        throw error;
    }
    throw new Error("Falha ao carregar o capítulo. Tente novamente ou verifique a conexão.");
  }
};

export const askBibleAssistant = async (query: string, context: string): Promise<string> => {
  const ai = getAI();
  if (!ai) return "Erro: API Key ausente.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `
        Contexto Atual (Capítulo sendo lido): ${context}

        Pergunta do Usuário: ${query}

        Instrução: Atue como um teólogo sábio, gentil e especialista bíblico. Responda à pergunta do usuário com base no contexto fornecido e no conhecimento geral bíblico. Use markdown para formatação. Seja conciso mas profundo.
      `
    });

    return response.text || "Desculpe, não consegui formular uma resposta.";
  } catch (error) {
    return "Erro ao consultar o assistente.";
  }
};

export const generateBibleCover = async (prompt: string): Promise<string> => {
  const ai = getAI();
  if (!ai) throw new Error("Chave de API não configurada.");

  try {
    const response = await ai.models.generateImages({
      model: 'imagen-4.0-generate-001',
      prompt: prompt,
      config: {
        numberOfImages: 1,
        aspectRatio: '3:4',
        outputMimeType: 'image/jpeg',
      },
    });

    const imageBytes = response.generatedImages?.[0]?.image?.imageBytes;
    if (imageBytes) {
      return `data:image/jpeg;base64,${imageBytes}`;
    }
    throw new Error("Nenhuma imagem gerada.");
  } catch (error) {
    console.error("Erro ao gerar capa:", error);
    throw new Error("Falha ao gerar a capa.");
  }
};

export const getVerseAudio = async (text: string): Promise<string> => {
  const ai = getAI();
  if (!ai) throw new Error("API Key missing");

  try {
    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: {
        parts: [{ text: text }],
        },
        config: {
        responseModalities: ["AUDIO"], 
        speechConfig: {
            voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Puck' },
            },
        },
        },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Não foi possível gerar o áudio.");
    return base64Audio;
  } catch (error) {
      console.error("Erro TTS:", error);
      throw error;
  }
}
```

## components/Reader.tsx

Substitui a lógica de Web Speech API por decodificação PCM e AudioContext para tocar o áudio gerado pelo Gemini.

```typescript
import React, { useRef, useEffect, useState, useCallback } from 'react';
import { BibleState, Verse } from '../types';
import { Loader2, ArrowLeft, ArrowRight, MessageCircleQuestion, Play, Pause, Square, Volume2 } from 'lucide-react';
import { getVerseAudio } from '../services/geminiService';

interface ReaderProps {
  state: BibleState;
  onChapterChange: (delta: number) => void;
  onToggleAI: () => void;
}

// Helper para decodificar PCM (Raw Audio) do Gemini
async function decodePCM(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      // Normaliza de Int16 (-32768 a 32767) para Float32 (-1.0 a 1.0)
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const Reader: React.FC<ReaderProps> = ({ state, onChapterChange, onToggleAI }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  // Audio State
  const [isPlaying, setIsPlaying] = useState(false);
  const [activeVerseNum, setActiveVerseNum] = useState<number | null>(null);
  const [loadingAudio, setLoadingAudio] = useState(false);

  // Audio Context Refs
  const audioCtxRef = useRef<AudioContext | null>(null);
  const sourceRef = useRef<AudioBufferSourceNode | null>(null);
  const isPlayingRef = useRef(false); // Ref para acesso dentro de loops/closures
  const versesRef = useRef<Verse[]>([]);

  // Scroll to top when chapter changes
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = 0;
    }
    stopAudio();
  }, [state.currentBook, state.currentChapter]);

  // Update verses ref
  useEffect(() => {
    if (state.content?.verses) {
        versesRef.current = state.content.verses;
    }
  }, [state.content]);

  // Cleanup
  useEffect(() => {
    return () => {
      stopAudio();
      if (audioCtxRef.current) {
        audioCtxRef.current.close();
      }
    };
  }, []);

  const initAudioContext = () => {
      if (!audioCtxRef.current) {
          const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
          audioCtxRef.current = new AudioContextClass({ sampleRate: 24000 });
      }
      if (audioCtxRef.current.state === 'suspended') {
          audioCtxRef.current.resume();
      }
      return audioCtxRef.current;
  };

  const stopAudio = () => {
    if (sourceRef.current) {
        try { sourceRef.current.stop(); } catch(e) {}
        sourceRef.current = null;
    }
    isPlayingRef.current = false;
    setIsPlaying(false);
    setActiveVerseNum(null);
    setLoadingAudio(false);
  };

  const playSpecificVerse = async (verse: Verse, onComplete?: () => void) => {
    // Se já estiver tocando este, para
    if (activeVerseNum === verse.number && isPlaying) {
        stopAudio();
        return;
    }

    // Para qualquer outro áudio
    if (sourceRef.current) {
        try { sourceRef.current.stop(); } catch(e) {}
    }

    setActiveVerseNum(verse.number);
    setIsPlaying(true);
    isPlayingRef.current = true;
    setLoadingAudio(true);

    try {
        const ctx = initAudioContext();

        // 1. Baixar Áudio
        const base64 = await getVerseAudio(verse.text);

        // Verifica se o usuário cancelou enquanto baixava
        if (!isPlayingRef.current || activeVerseNum !== verse.number && activeVerseNum !== null) return;

        // 2. Decodificar Base64 para Uint8Array
        const binaryString = atob(base64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

        // 3. Decodificar PCM para AudioBuffer
        const audioBuffer = await decodePCM(bytes, ctx);

        // 4. Tocar
        const source = ctx.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(ctx.destination);

        source.onended = () => {
            sourceRef.current = null;
            if (onComplete && isPlayingRef.current) {
                onComplete();
            } else {
                setIsPlaying(false);
                setActiveVerseNum(null);
                isPlayingRef.current = false;
            }
        };

        sourceRef.current = source;
        setLoadingAudio(false);

        // Auto-scroll
        const element = document.getElementById(`verse-${verse.number}`);
        if (element) {
            element.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }

        source.start(0);

    } catch (error) {
        console.error("Erro ao reproduzir áudio:", error);
        stopAudio();
        alert("Erro ao reproduzir áudio. Verifique sua conexão.");
    }
  };

  const playChapter = useCallback(async (startIndex = 0) => {
    const verses = versesRef.current;
    if (!verses || startIndex >= verses.length) {
        stopAudio();
        return;
    }

    // Se for o início, garante que o estado de playing está true
    if (startIndex === 0) {
        setIsPlaying(true);
        isPlayingRef.current = true;
    }

    const verse = verses[startIndex];

    // Toca o versículo atual e agenda o próximo no callback onComplete
    await playSpecificVerse(verse, () => {
        // Pequeno delay para naturalidade entre versículos
        setTimeout(() => {
            if (isPlayingRef.current) {
                playChapter(startIndex + 1);
            }
        }, 300);
    });
  }, []);

  const togglePlayChapter = () => {
    if (isPlaying) {
        stopAudio();
    } else {
        playChapter(0);
    }
  };

  if (state.isLoading) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center h-full bg-bible-paper">
        <Loader2 className="w-12 h-12 text-bible-gold animate-spin mb-4" />
        <p className="text-stone-500 animate-pulse font-serif">Buscando as escrituras sagradas...</p>
      </div>
    );
  }

  if (state.error) {
    return (
      <div className="flex-1 flex items-center justify-center bg-bible-paper p-8 text-center">
        <div className="max-w-md">
          <p className="text-red-600 font-semibold mb-2">Ocorreu um erro</p>
          <p className="text-stone-600 mb-4">{state.error}</p>
          <button 
            onClick={() => window.location.reload()} 
            className="px-4 py-2 bg-bible-leather text-white rounded hover:bg-stone-800"
          >
            Tentar Novamente
          </button>
        </div>
      </div>
    );
  }

  if (!state.content) return null;

  return (
    <div className="flex-1 bg-bible-paper relative h-full overflow-hidden flex flex-col">
      {/* Top Bar inside Reader */}
      <div className="sticky top-0 z-10 bg-bible-paper/95 backdrop-blur border-b border-stone-200 p-3 md:p-4 flex justify-between items-center shadow-sm">
         <div className="flex items-baseline gap-2 overflow-hidden">
            <h2 className="text-lg md:text-2xl font-bold font-serif text-bible-ink truncate">
                {state.currentBook.name}
            </h2>
            <span className="text-bible-gold text-xl md:text-3xl font-serif">{state.currentChapter}</span>
         </div>

         <div className="flex items-center gap-2 md:gap-3">
            {/* Audio Control */}
            <button 
                onClick={togglePlayChapter}
                className={`flex items-center gap-2 px-3 py-1.5 text-sm rounded-full transition-all border ${
                    isPlaying && !activeVerseNum // Playing chapter general state
                    ? 'bg-red-50 text-red-600 border-red-200 hover:bg-red-100' 
                    : 'bg-stone-100 text-stone-600 border-stone-200 hover:bg-stone-200'
                }`}
                title={isPlaying ? "Parar Leitura" : "Ouvir Capítulo"}
            >
                {isPlaying ? <Square className="w-4 h-4 fill-current" /> : <Play className="w-4 h-4 fill-current" />}
                <span className="hidden sm:inline font-medium">{isPlaying ? "Parar" : "Ouvir"}</span>
            </button>

            {/* AI Button */}
            <button 
                onClick={onToggleAI}
                className="flex items-center gap-2 px-3 py-1.5 text-sm bg-indigo-50 text-indigo-700 rounded-full hover:bg-indigo-100 transition-colors border border-indigo-200"
            >
                <MessageCircleQuestion className="w-4 h-4" />
                <span className="hidden sm:inline">Estudo AI</span>
            </button>
         </div>
      </div>

      {/* Content Scroll Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 md:p-12 max-w-4xl mx-auto w-full pb-32">

        {/* AI Summary Banner */}
        {state.content.summary && (
            <div className="mb-8 p-6 bg-stone-100 rounded-xl border-l-4 border-bible-gold italic text-stone-600 font-serif text-sm leading-relaxed">
                <span className="block font-bold text-bible-gold mb-1 not-italic text-xs uppercase tracking-widest">Resumo do Capítulo</span>
                {state.content.summary}
            </div>
        )}

        {/* Verses */}
        <div className="space-y-1">
            {state.content.verses.map((verse) => (
                <div 
                    id={`verse-${verse.number}`}
                    key={verse.number} 
                    className={`relative group rounded-lg transition-all duration-500 ${
                        activeVerseNum === verse.number 
                        ? 'bg-bible-gold/15 py-4 px-4 -mx-4 shadow-sm ring-1 ring-bible-gold/20' 
                        : 'hover:bg-stone-50 py-1'
                    }`}
                >
                    <p className="text-lg md:text-xl leading-loose font-serif text-bible-ink relative">
                        {/* Verse Number */}
                        <sup className={`text-xs font-bold mr-2 select-none font-sans transition-colors ${
                            activeVerseNum === verse.number ? 'text-bible-leather' : 'text-bible-gold'
                        }`}>
                            {verse.number}
                        </sup>

                        {/* Text */}
                        {verse.text}

                        {/* Inline Play Button (Visible on Hover or Active) */}
                        <button
                            onClick={() => playSpecificVerse(verse)}
                            className={`absolute -left-8 top-1.5 p-1.5 rounded-full transition-opacity ${
                                activeVerseNum === verse.number ? 'opacity-100 text-bible-leather' : 'opacity-0 group-hover:opacity-100 text-stone-400 hover:text-bible-gold'
                            } hidden md:inline-flex`}
                            title="Ouvir este versículo"
                        >
                            {activeVerseNum === verse.number ? (
                                loadingAudio ? <Loader2 className="w-4 h-4 animate-spin" /> : <Volume2 className="w-4 h-4 animate-pulse" />
                            ) : (
                                <Play className="w-3 h-3" />
                            )}
                        </button>
                    </p>
                </div>
            ))}
        </div>

        {/* Navigation Footer */}
        <div className="mt-16 pt-8 border-t border-stone-200 flex justify-between items-center">
            <button 
                onClick={() => onChapterChange(-1)}
                disabled={state.currentBook.name === 'Gênesis' && state.currentChapter === 1}
                className="flex items-center gap-2 text-stone-500 hover:text-bible-leather disabled:opacity-30 disabled:cursor-not-allowed transition-colors group"
            >
                <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                <span className="font-sans font-medium">Anterior</span>
            </button>

            <span className="text-stone-400 text-sm font-sans">
                {state.currentBook.name} {state.currentChapter}
            </span>

            <button 
                onClick={() => onChapterChange(1)}
                disabled={state.currentBook.name === 'Apocalipse' && state.currentChapter === 22}
                className="flex items-center gap-2 text-stone-500 hover:text-bible-leather disabled:opacity-30 disabled:cursor-not-allowed transition-colors group"
            >
                <span className="font-sans font-medium">Próximo</span>
                <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
            </button>
        </div>
      </div>
    </div>
  );
};
```

